const express = require('express');
const fs = require('fs');
const { Parser } = require('xml2js');

const app = express();
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

// Define allowed XML files extensions
const xmlExtensions = ['.xml', '.XML'];

// Function to parse XML and extract configuration settings into a JS object
function parseXml(fileContent) {
    try {
        const parser = new Parser({ headless: true });
        const xmlObject = parser.parseStringSync(fileContent);
        // To be implemented according to the specific XML schema
        return { 
            setting1: 'value',
            setting2: 'value' 
        };
    } catch (error) {
        console.error(`Error parsing XML: ${error}`);
        return null;
    }
}

// Handle multipart/form-data form submissions with uploaded files
app.post('/upload', (req, res) => {
    const file = req.files.file;

    // Check if the uploaded file has a supported extension
    if (!xmlExtensions.includes(file.mimetype)) {
        return res.status(400).send({ error: 'Only XML files are allowed' });
    }

    // Read the contents of the uploaded file
    const readStream = fs.createReadStream(file.path);
    let xmlContent = '';

    readStream.on('data', (chunk) => {
        xmlContent += chunk.toString();
    });

    readStream.on('end', () => {
        const jsObject = parseXml(xmlContent);

        if (!jsObject) {
            return res.status(500).send({ error: 'Failed to parse XML' });
        }

        // Store the extracted configuration settings in a database or another storage
        console.log(jsObject);

        fs.unlink(file.path, (err) => {
            if (err) {
                console.error(`Error deleting uploaded file: ${err}`);
                return res.status(500).send({ error: 'Failed to delete uploaded file' });
            }
        });

        res.send({ message: 'XML parsed successfully' });
    });

    readStream.on('error', (err) => {
        if (err.code === 'ENOENT') {
            console.error(`Error reading uploaded file: ${err}`);
            return res.status(500).send({ error: 'Failed to read uploaded file' });
        }
    });
});

// Start the server
const port = 3000;
app.listen(port, () => {
    console.log(`Server listening on port ${port}`);
});